import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import '@fortawesome/fontawesome-free/css/all.min.css';

const Register = () => {
  const [formData, setFormData] = useState({
    Username: '',
    Password: '',
    ClientCode: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const validatePassword = (password) => {
    const errors = [];
    if (!/[A-Z]/.test(password)) {
      errors.push("Password must have at least one uppercase letter ('A'-'Z')");
    }
    if (!/[0-9]/.test(password)) {
      errors.push("Password must have at least one digit ('0'-'9')");
    }
    if (!/[^A-Za-z0-9]/.test(password)) {
      errors.push("Password must have at least one non-alphanumeric character");
    }
    return errors;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const passwordErrors = validatePassword(formData.Password);
    if (passwordErrors.length > 0) {
      setError(passwordErrors.join('\n'));
      setLoading(false);
      return;
    }
    try {
      await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthRegister', formData);
      toast.success('Registration successful! Please login.', {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
      navigate('/login');
    } catch (err) {
      const errorMessage = err.response?.data || 'Registration failed. Please try again.';
      setError(Array.isArray(errorMessage) ? errorMessage.map(e => e.Description).join('\n') : errorMessage);
      toast.error('Registration failed. Please check the requirements.', {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f5f7fa 0%, #e0e6ed 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif'
    }}>
      <ToastContainer />
      <div style={{
        minWidth: 400,
        maxWidth: 480,
        width: '100%',
        background: 'rgba(255, 255, 255, 0.95)',
        borderRadius: 24,
        boxShadow: '0 10px 40px 0 rgba(31, 38, 135, 0.15)',
        backdropFilter: 'blur(10px)',
        border: '1px solid rgba(255, 255, 255, 0.5)',
        padding: '3rem 2.8rem',
        margin: '2rem 0'
      }}>
        <div className="text-center mb-4">
          <div style={{ 
            width: 75,
            height: 75,
            backgroundColor: '#5470FF',
            borderRadius: '50%',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            margin: '0 auto 1.2rem',
            boxShadow: '0 8px 24px rgba(84, 112, 255, 0.3)',
            background: 'linear-gradient(45deg, #5470FF, #6C8FFF)'
          }}>
            <i className="fas fa-user-plus fa-2x" style={{ color: 'white' }}></i>
          </div>
          <h3 className="mb-1 fw-bold" style={{ 
            fontSize: '1.8rem', 
            color: '#333',
            textAlign: 'center', 
            letterSpacing: 0.5
          }}>Create Account</h3>
          <p style={{ color: '#666', fontSize: '1rem' }}>Register to access the RFID API Dashboard</p>
        </div>

        {error && (
          <div className="alert alert-danger py-2" style={{ 
            fontSize: '0.98rem',
            borderRadius: '14px',
            border: 'none',
            background: 'rgba(220, 53, 69, 0.1)',
            color: '#dc3545'
          }}>{error}</div>
        )}
        
        <form onSubmit={handleSubmit} autoComplete="off">
          <div className="mb-4">
            <label htmlFor="Username" className="form-label" style={{ 
              fontWeight: 600, 
              color: '#444',
              fontSize: '0.95rem',
              marginBottom: '0.5rem'
            }}>
              <i className="fas fa-user me-2" style={{ color: '#5470FF' }}></i>
              Username
            </label>
            <div className="input-group">
              <span className="input-group-text" style={{ 
                background: '#5470FF', 
                border: 'none', 
                borderTopLeftRadius: '14px', 
                borderBottomLeftRadius: '14px' 
              }}>
                <i className="fas fa-user text-white"></i>
              </span>
              <input
                type="text"
                className="form-control"
                id="Username"
                name="Username"
                value={formData.Username}
                onChange={handleChange}
                required
                placeholder="Enter your email or username"
                style={{ 
                  fontSize: '1.05rem', 
                  background: 'rgba(255, 255, 255, 0.9)',
                  border: '1px solid #e0e0e0', 
                  borderTopRightRadius: '14px',
                  borderBottomRightRadius: '14px',
                  borderLeft: 'none',
                  padding: '0.7rem 1rem',
                  transition: 'all 0.3s',
                  boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
                }}
              />
            </div>
          </div>
          
          <div className="mb-4">
            <label htmlFor="ClientCode" className="form-label" style={{ 
              fontWeight: 600, 
              color: '#444',
              fontSize: '0.95rem',
              marginBottom: '0.5rem'
            }}>
              <i className="fas fa-building me-2" style={{ color: '#5470FF' }}></i>
              Client Code
            </label>
            <div className="input-group">
              <span className="input-group-text" style={{ 
                background: '#5470FF', 
                border: 'none', 
                borderTopLeftRadius: '14px', 
                borderBottomLeftRadius: '14px' 
              }}>
                <i className="fas fa-building text-white"></i>
              </span>
              <input
                type="text"
                className="form-control"
                id="ClientCode"
                name="ClientCode"
                value={formData.ClientCode}
                onChange={handleChange}
                required
                placeholder="Enter your client code"
                style={{ 
                  fontSize: '1.05rem', 
                  background: 'rgba(255, 255, 255, 0.9)',
                  border: '1px solid #e0e0e0', 
                  borderTopRightRadius: '14px',
                  borderBottomRightRadius: '14px',
                  borderLeft: 'none',
                  padding: '0.7rem 1rem',
                  transition: 'all 0.3s',
                  boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
                }}
              />
            </div>
          </div>
          
          <div className="mb-4">
            <label htmlFor="Password" className="form-label" style={{ 
              fontWeight: 600, 
              color: '#444',
              fontSize: '0.95rem',
              marginBottom: '0.5rem'
            }}>
              <i className="fas fa-lock me-2" style={{ color: '#5470FF' }}></i>
              Password
            </label>
            <div className="input-group">
              <span className="input-group-text" style={{ 
                background: '#5470FF', 
                border: 'none', 
                borderTopLeftRadius: '14px', 
                borderBottomLeftRadius: '14px' 
              }}>
                <i className="fas fa-lock text-white"></i>
              </span>
              <input
                type="password"
                className="form-control"
                id="Password"
                name="Password"
                value={formData.Password}
                onChange={handleChange}
                required
                placeholder="Create a strong password"
                style={{ 
                  fontSize: '1.05rem', 
                  background: 'rgba(255, 255, 255, 0.9)',
                  border: '1px solid #e0e0e0', 
                  borderTopRightRadius: '14px',
                  borderBottomRightRadius: '14px',
                  borderLeft: 'none',
                  padding: '0.7rem 1rem',
                  transition: 'all 0.3s',
                  boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
                }}
              />
            </div>
            <div style={{ 
              backgroundColor: 'rgba(84, 112, 255, 0.05)', 
              padding: '12px 16px', 
              borderRadius: '10px', 
              marginTop: '12px',
              border: '1px solid rgba(84, 112, 255, 0.2)'
            }}>
              <div className="d-flex align-items-center">
                <div style={{
                  width: 28,
                  height: 28,
                  backgroundColor: '#5470FF',
                  borderRadius: '50%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginRight: '10px'
                }}>
                  <i className="fas fa-shield-alt text-white" style={{ fontSize: '0.9rem' }}></i>
                </div>
                <span style={{ 
                  color: '#444', 
                  fontWeight: 600, 
                  fontSize: '0.95rem'
                }}>Password must contain:</span>
              </div>
              <ul className="mb-0 mt-2" style={{ paddingLeft: '2.3rem', color: '#555' }}>
                <li>At least one uppercase letter</li>
                <li>At least one number</li>
                <li>At least one special character</li>
              </ul>
            </div>
          </div>
          
          <button
            type="submit"
            className="btn w-100 fw-bold"
            style={{
              fontSize: '1.1rem',
              background: 'linear-gradient(45deg, #5470FF, #6C8FFF)',
              color: '#fff',
              border: 'none',
              borderRadius: 14,
              padding: '0.8rem',
              marginTop: 12,
              marginBottom: 16,
              boxShadow: '0 4px 14px rgba(84, 112, 255, 0.3)',
              transition: 'all 0.3s'
            }}
            disabled={loading}
            onMouseOver={(e) => {
              e.currentTarget.style.background = 'linear-gradient(45deg, #4560EB, #5A7DF0)';
              e.currentTarget.style.transform = 'translateY(-2px)';
              e.currentTarget.style.boxShadow = '0 6px 20px rgba(84, 112, 255, 0.4)';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.background = 'linear-gradient(45deg, #5470FF, #6C8FFF)';
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = '0 4px 14px rgba(84, 112, 255, 0.3)';
            }}
          >
            {loading ? (
              <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
            ) : (
              <>
                <i className="fas fa-user-plus me-2"></i>
                Create Account
              </>
            )}
          </button>
        </form>
        
        <div className="text-center mt-4" style={{ fontSize: '1rem', color: '#555' }}>
          Already have an account?{' '}
          <span
            className="fw-bold"
            style={{ 
              color: '#5470FF', 
              cursor: 'pointer',
              textDecoration: 'underline',
              transition: 'all 0.3s'
            }}
            onClick={() => navigate('/login')}
          >
            Log in now
          </span>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Register;
